def solve_8d510a79(grid):
    rows, cols = len(grid), len(grid[0])
    out = copy.deepcopy(grid)
    five_row = None
    for r in range(rows):
        if all(v == 5 for v in grid[r]):
            five_row = r
            break
    for r in range(rows):
        for c in range(cols):
            v = grid[r][c]
            if v == 0 or v == 5:
                continue
            if v == 1:
                if r < five_row:
                    for rr in range(r - 1, -1, -1):
                        out[rr][c] = 1
                else:
                    for rr in range(r + 1, rows):
                        out[rr][c] = 1
            elif v == 2:
                if r < five_row:
                    for rr in range(r + 1, five_row):
                        out[rr][c] = 2
                else:
                    for rr in range(r - 1, five_row, -1):
                        out[rr][c] = 2
    return out

