def solve_90f3ed37(grid):
    rows, cols = len(grid), len(grid[0])
    out = copy.deepcopy(grid)

    groups = []
    i = 0
    while i < rows:
        if any(v == 8 for v in grid[i]):
            start = i
            while i < rows and any(v == 8 for v in grid[i]):
                i += 1
            groups.append((start, i))
        else:
            i += 1

    template = None
    template_data = None
    for s, e in groups:
        covered = set()
        for r in range(s, e):
            for c in range(cols):
                if grid[r][c] == 8:
                    covered.add(c)
        if len(covered) == cols:
            template = (s, e)
            template_data = [grid[r][:] for r in range(s, e)]
            break

    if template is None:
        return out

    tlen = len(template_data)

    for s, e in groups:
        if (s, e) == template:
            continue

        glen = e - s
        covered = set()
        for r in range(s, e):
            for c in range(cols):
                if grid[r][c] == 8:
                    covered.add(c)

        if glen == tlen:
            for i in range(glen):
                gr = s + i
                for c in range(cols):
                    if template_data[i][c] == 8 and out[gr][c] == 0 and c not in covered:
                        out[gr][c] = 1
        elif glen < tlen:
            for i in range(glen):
                gr = s + i
                for c in range(cols):
                    if template_data[i][c] == 8 and out[gr][c] == 0 and c not in covered:
                        out[gr][c] = 1
            insert_r = e
            for i in range(glen, tlen):
                if insert_r < rows:
                    for c in range(cols):
                        if template_data[i][c] == 8 and c not in covered:
                            out[insert_r][c] = 1
                    insert_r += 1

    return out

