def solve_913fb3ed(grid):
    rows, cols = len(grid), len(grid[0])
    out = [[0]*cols for _ in range(rows)]
    color_map = {3: 6, 2: 1, 8: 4}
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] != 0:
                val = grid[r][c]
                border = color_map.get(val, val)
                for dr in range(-1, 2):
                    for dc in range(-1, 2):
                        nr, nc = r+dr, c+dc
                        if 0 <= nr < rows and 0 <= nc < cols:
                            if dr == 0 and dc == 0:
                                out[nr][nc] = val
                            else:
                                out[nr][nc] = border
    return out

