def solve_9172f3a0(grid):
    n = len(grid)
    scale = n
    out = []
    for r in range(n):
        for _ in range(scale):
            row = []
            for c in range(n):
                row.extend([grid[r][c]] * scale)
            out.append(row)
    return out
